mapper.select:
select CONCAT(SO.COMPKEY , SO.WAREKEY, SO.COOUTKY) as ROWKEY , SO.COMPKEY , SO.WAREKEY as WAREKEY , SO.OWNERKY , (select OWNAMLC from MOWRMA where COMPKEY = SO.COMPKEY and OWNERKY = SO.OWNERKY ) as OWNAMLC , SO.DOCCATE as DOCCATE , SO.DOCTYPE as DOCTYPE , SO.DOCTYNM as DOCTYNM , SO.COOUTKY as COOUTKY , SO.SHPDCKY as SHPDCKY , SO.DCTCTYP as DCTCTYP , COUNT(SO.COOUTIT) as REFSCNT , MIN(SO.STOCKYN) as STOCKYN , SUM(SO.SHCUQTY) as SHCUQTY , SUM(SO.RGITQTY) as RGITQTY , SUM(SO.SHALQTY) as SHALQTY , date_format(SO.SALRQDT, '%Y-%m-%d') as SALRQDT , date_format(SO.SALRQTM, '%H:%i:%s') as SALRQTM , SO.UPDTCHK from ( select SH.COMPKEY , SH.DOCCATE , SH.DOCTYPE , ( select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE and WAREKEY = SH.WAREKEY ) as DOCTYNM, SH.WAREKEY as WAREKEY , SH.OWNERKY as OWNERKY , SH.CUSTKEY as CUSTKEY , SH.COOUTKY as COOUTKY , SH.COOUTIT as COOUTIT , SH.SHPDCKY as SHPDCKY , SH.DCTCTYP as DCTCTYP , SH.SKUMKEY as SKUMKEY , (case when IFNULL(ST.TOTQTY,0) - SH.RGITQTY - SH.SHALQTY < 0 then 'N' else 'Y' end) as STOCKYN, SH.SHCUQTY as SHCUQTY , SH.RGITQTY as RGITQTY , SH.SHALQTY as SHALQTY, SH.SALRQDT as SALRQDT , SH.SALRQTM as SALRQTM , SH.UPDTCHK from WSHPIT SH FORCE INDEX(IX_WSHPIT02) inner join MSKUWC MS on MS.COMPKEY = SH.COMPKEY and MS.WAREKEY = SH.WAREKEY and MS.OWNERKY = SH.OWNERKY and MS.SKUMKEY = SH.SKUMKEY left join ( select COMPKEY , OWNERKY , WAREKEY , SKUMKEY , SKUDESC , LOTAT17 , LOTAT18, LOTAT19, LOTAT20, (sum(STOTQTY)- sum(SBLOQTY)) as TOTQTY from WSTKKY FORCE INDEX(IX_WSTKKY02) where COMPKEY = #{userData.compkey} and WAREKEY = #{warekey} and AREAKEY = 'STG' and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by COMPKEY , WAREKEY , OWNERKY , SKUMKEY , LOTAT17 , LOTAT18 , LOTAT19 , LOTAT20 ) ST on SH.COMPKEY = ST.COMPKEY and SH.WAREKEY = ST.WAREKEY and SH.OWNERKY = ST.OWNERKY and SH.SKUMKEY = ST.SKUMKEY and (case when SH.DCTCTYP = 'TC' then SH.COOUTKY else ' ' end) = ST.LOTAT19 and (case when SH.DCTCTYP = 'TC' then SH.COOUTIT else ' ' end) = ST.LOTAT20 SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and SH.DOCCATE = '700' and SH.DOCTYPE not in('780' , '781')
and SH.OWNERKY = #{ownerky}
and SH.COOUTKY in ( select distinct COOUTKY from WSHPIT w FORCE INDEX(IX_WSHPIT01) w.COMPKEY = #{userData.compkey} and w.WAREKEY = #{warekey}
and w.OWNERKY = #{ownerky}
and w.SHPPDAY between #{shppdayfrom} and #{shppdayto}
and w.SHPDCST in
#{shpdcstItem}
and w.SHPITST in
#{shpdcstItem}
, 'F_ALOC'
and w.COOUTKY = #{cooutky}
and w.SHPDCKY = #{shpdcky}
)
and SH.SHPDCST in
#{shpdcstItem}
and SH.SHPITST in
#{shpdcstItem}
, 'F_ALOC'
and SH.SKUDESC LIKE CONCAT('%' , #{skudesc} , '%')
) SO group by SO.COOUTKY order by SO.COOUTKY

select CONCAT(SH.COMPKEY , SH.COOUTKY, SH.COOUTIT) as ROWKEY , SH.COMPKEY , SH.DOCCATE , SH.DOCTYPE , SH.SHPDCKY , SH.SHPDCIT , SH.SHPDCST , (select COMCDTX from MCODEM MC where MC.COMPKEY = SH.COMPKEY and MC.COMCDVL = SH.SHPDCST and MC.COMCDKY = 'SHPDCST') as SHPDCNM , SH.SHPITST , (select COMCDTX from MCODEM MC where MC.COMPKEY = SH.COMPKEY and MC.COMCDVL = SH.SHPDCST and MC.COMCDKY = 'SHPITST') as SHPITNM , (select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE and WAREKEY = SH.WAREKEY ) as DOCTYNM , SH.WAREKEY , SH.OWNERKY , (select OWNAMLC from MOWRMA where COMPKEY = SH.COMPKEY and OWNERKY = SH.OWNERKY ) as OWNAMLC , SH.COOUTKY as COOUTKY , SH.COOUTIT as COOUTIT , SH.DCTCTYP as DCTCTYP , SH.SKUMKEY as SKUMKEY , CONCAT("(", IFNULL(ST.TOTQTY,0),") ", SH.SKUDESC) as SKUDESC , MS.SUOMKEY as SUOMKEY , (case when IFNULL(ST.TOTQTY,0) - SH.RGITQTY - SH.SHALQTY < 0 then 'N' else 'Y' end) as STOCKYN , IFNULL(ST.TOTQTY,0) as STOCKCT , SH.SHCUQTY as SHCUQTY , SH.RGITQTY as RGITQTY , SH.SHALQTY as SHALQTY , SH.SHPKQTY as SHPKQTY , SH.SHCFQTY as SHCFQTY , fn_com_todate(SH.SALRQDT) as SALRQDT , fn_com_totime(SH.SALRQTM) as SALRQTM , SH.ALLGRKY , fn_com_todate(SH.SHPPDAY) as SHPPDAY , fn_com_totime(SH.SHPPTIM) as SHPPTIM , fn_com_todate(SH.SHPSDAY) as SHPSDAY , fn_com_totime(SH.SHPSTIM) as SHPSTIM , SH.SPEHTIM , SH.SPEITIM , ' ' as ALSTRKY from WSHPIT SH FORCE INDEX(IX_WSHPIT01) inner join MSKUWC MS on MS.COMPKEY = SH.COMPKEY and MS.WAREKEY = SH.WAREKEY and MS.OWNERKY = SH.OWNERKY and MS.SKUMKEY = SH.SKUMKEY left join ( select t.COMPKEY, t.WAREKEY, t.OWNERKY, t.SKUMKEY, t.SHPDCKY, t.SHPDCIT, t.ALLGRKY, t.COOUTKY, t.COOUTIT, SUM(t.FORDQTY) AS FORDQTY, SUM(t.TCMPQTY) AS TCMPQTY from WTAKIT t t.COMPKEY = #{userData.compkey} and t.WAREKEY = #{warekey} and t.DOCCATE = '500' and t.DOCTYPE = '530' and t.TASKSTS IN ('NEW','TASK','TSCOMP')
and t.OWNERKY = #{ownerky}
group by t.COMPKEY, t.WAREKEY, t.OWNERKY, t.SKUMKEY, t.SHPDCKY, t.SHPDCIT, t.COOUTKY , t.COOUTIT, t.ALLGRKY ) TK ON SH.COMPKEY = TK.COMPKEY and SH.WAREKEY = TK.WAREKEY and SH.OWNERKY = TK.OWNERKY and SH.SKUMKEY = TK.SKUMKEY and SH.SHPDCKY = TK.SHPDCKY and SH.SHPDCIT = TK.SHPDCIT and SH.COOUTKY = TK.COOUTKY and SH.COOUTIT = TK.COOUTIT and SH.ALLGRKY = TK.ALLGRKY left join ( select COMPKEY , OWNERKY , WAREKEY , SKUMKEY , SKUDESC , LOTAT17 , LOTAT18 , LOTAT19 , LOTAT20 , (sum(STOTQTY)- sum(SBLOQTY)) as TOTQTY from WSTKKY FORCE INDEX(IX_WSTKKY02) COMPKEY = #{userData.compkey} and WAREKEY = #{warekey} and AREAKEY = 'STG' and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0
group by COMPKEY , WAREKEY , OWNERKY , SKUMKEY , LOTAT17 , LOTAT18 , LOTAT19 , LOTAT20 ) ST on SH.COMPKEY = ST.COMPKEY and SH.WAREKEY = ST.WAREKEY and SH.OWNERKY = ST.OWNERKY and SH.SKUMKEY = ST.SKUMKEY and (case when SH.DCTCTYP = 'TC' then SH.COOUTKY else ' ' end) = ST.LOTAT19 and (case when SH.DCTCTYP = 'TC' then SH.COOUTIT else ' ' end) = ST.LOTAT20 SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and SH.DOCCATE = '700' and SH.DOCTYPE not in ('780' , '781')
and SH.OWNERKY = #{ownerky}
and SH.SHPPDAY between #{shppdayfrom} and #{shppdayto}
and SH.SHPDCST in
#{shpdcstItem}
and SH.SHPITST in
#{shpdcstItem}
, 'F_ALOC'
and SH.SHPDCKY = #{shpdcky}
and SH.COOUTKY = #{cooutky}
and SH.SKUDESC LIKE CONCAT('%' , #{skudesc} , '%')
order by SH.COOUTKY, SH.COOUTIT

update.foreach:
    	update WSHPIT
		   set LMODATE = to_char(now(),'YYYYMMDD')
			 , LMOTIME = to_char(now(),'hh24miss')
			 , LMOUSER = #{item.userData.useract}
			 , RGITQTY = #{item.rgitqty}
			 , ALLGRKY = #{item.allgrky}
			 , PICKTYP = #{item.picktyp}
			 , MOVTEAM = #{item.movteam}
    	 where COMPKEY = #{item.compkey}
    	   and OWNERKY = #{item.ownerky}
    	   and WAREKEY = #{item.warekey}
    	   and SHPDCKY = #{item.shpdcky}
    	   and SHPDCIT = #{item.shpdcit}
    	   and UPDTCHK = #{item.updtchk}

 	update WSHPIT
		   set LMODATE = to_char(now(),'YYYYMMDD')
 		 , LMOTIME = to_char(now(),'hh24miss')
 		 , LMOUSER = #{item.userData.useract}
 		 , SHPDCST = (
 						select  
                           	 case when sum(SHALQTY) > 0 then 
                              case when sum(RGITQTY) = sum(SHALQTY) then 'F_ALOC'
                              else 'P_ALOC' end 
                           else 'NEW' end 
                           from  WSHPIT
                           where COMPKEY = #{item.compkey} 
                             and SHPDCKY = #{item.shpdcky}
                           group by SHPDCKY 
                     )
 	where COMPKEY = #{item.compkey}
 	  and OWNERKY = #{item.ownerky}
 	  and WAREKEY = #{item.warekey}
 	  and SHPDCKY = #{item.shpdcky}
 	  and UPDTCHK = #{item.updtchk}

mapper.select:

CALL sp_wm_allocate_grp
( 
	  #{compkey}
	, #{warekey}
	, #{allgrky}
	, #{lmouser}
	, #{omsgkey, mode=OUT, jdbcType=VARCHAR}
	, #{oresult, mode=OUT, jdbcType=INTEGER}
)


CALL sp_wm_ctrstokky_cancel
( 
	  #{userData.compkey}
	, #{warekey}
	, #{doccate}
	, #{doctype}


		, #{cooutky}
		, 0


		, #{cooutky}
		, #{cooutit}


		, #{allgrky}
		, '1'


		, #{shpdcky}
		, #{shpdcit}


		, #{taskoky}
		, #{taskoit}


	, #{userData.useract}
	, #{omsgkey, mode=OUT, jdbcType=VARCHAR}
	, #{oresult, mode=OUT, jdbcType=INTEGER}
)

select count(allgrky) 
  from WTAKIT 
 where COMPKEY = #{compkey}
   and WAREKEY = #{warekey}
   and ALLGRKY = #{allgrky}
   and TASKSTS = 'TASK'

select concat(SH.COMPKEY, SH.WAREKEY, SH.ALLGRKY, TS.PICKTYP) as ROWKEY , SH.COMPKEY , SH.WAREKEY , SH.OWNERKY , (select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE and WAREKEY = SH.WAREKEY) as DOCTYNM , TS.TASKOKY , TS.TASKOIT , TS.ALLGRKY , TS.PICKTYP , (select COMCDTX from MCODEM MC where MC.COMPKEY = SH.COMPKEY and MC.COMCDVL = TS.PICKTYP and MC.COMCDKY = 'PICKTYP') as PICKNAM , SH.SHPDCKY , SH.SHPDCIT , SH.COOUTKY , SH.COOUTIT , SH.OERETKY , SH.OERETIT , SH.SHCUQTY , SH.RGITQTY , SH.SHALQTY , TS.STKOTKY , TS.FRAREKY , TS.FRZONKY , TS.FRLOCKY , TS.FRARENM , TS.FRZONNM , TS.FRLOCNM , TS.TOAREKY , TS.TOZONKY , TS.TOLOCKY , TS.SKUMKEY , TS.SKUDESC , TS.FORDQTY , SH.SHPKQTY , SH.SHCFQTY , SH.SHPSDAY , SH.SHPSTIM , fn_com_todate(SH.CREDATE) as CREDATE , fn_com_totime(SH.CRETIME) as CRETIME , fn_sy_usernam(SH.COMPKEY, SH.LMOUSER) as CRENAME from WSHPIT SH FORCE INDEX(IX_WSHPIT01) inner join ( select COMPKEY , WAREKEY , OWNERKY , ALLGRKY , PICKTYP , COOUTKY , COOUTIT , TASKOKY , TASKOIT , STKOTKY , FORDQTY , TCMPQTY , OERETKY , OERETIT , FRAREKY , FRZONKY , FRLOCKY , (select AREANAM from MAREMA m where t.COMPKEY = m.COMPKEY and t.WAREKEY = m.WAREKEY and t.FRAREKY = m.AREAKEY) as FRARENM , (select ZONENAM from MZONMA m where t.COMPKEY = m.COMPKEY and t.WAREKEY = m.WAREKEY and t.FRAREKY = m.AREAKEY and t.FRZONKY = m.ZONEKEY) as FRZONNM , (select LOCANAM from MLOCMA m where t.COMPKEY = m.COMPKEY and t.WAREKEY = m.WAREKEY and t.FRAREKY = m.AREAKEY and t.FRZONKY = m.ZONEKEY and t.FRLOCKY = m.LOCAKEY) as FRLOCNM , TOAREKY , TOZONKY , TOLOCKY , SKUMKEY , SKUDESC from WTAKIT t where t.COMPKEY = #{userData.compkey} and t.WAREKEY = #{warekey} and t.DOCCATE = '500' and t.DOCTYPE = '530' and t.TASKSTS in ('TASK') ) TS on SH.COMPKEY = TS.COMPKEY and SH.WAREKEY = TS.WAREKEY and SH.OWNERKY = TS.OWNERKY and SH.COOUTKY = TS.COOUTKY and SH.COOUTIT = TS.COOUTIT and SH.OERETKY = TS.OERETKY and SH.OERETIT = TS.OERETIT SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and SH.DOCCATE = '700' and SH.DOCTYPE in ('710', '720', '730', '750','760','790', '780') and trim(TS.ALLGRKY) != '' and SH.SHPDCST not in ('SHPOUT') and SH.SHPITST not in ('SHPOUT')
and SH.OWNERKY = #{ownerky}
and TS.ALLGRKY = #{allgrky}
and TS.PICKTYP = #{picktyp}
and SH.SHPPDAY between #{shsdatefrom} and #{shsdateto}
group by TS.COMPKEY , TS.TASKOKY , TS.TASKOIT , TS.COOUTKY , TS.COOUTIT , TS.SKUMKEY , TS.SKUDESC , TS.STKOTKY order by SH.SHPDCKY , SHPDCIT , TASKOKY , TASKOIT ASC


CALL sp_wm_ctrstokky_cancel
(    #{userData.compkey}
   , #{warekey}
   , #{doccate}
   , #{doctype}
   , #{taskoky}
   , #{taskoit}
   , #{userData.useract}
   , #{omsgkey, mode=OUT, jdbcType=VARCHAR}
   , #{oresult, mode=OUT, jdbcType=INTEGER}
)


CALL sp_wm_allocate_change
(    #{compkey}
   , #{warekey}
   , #{doccate}
   , #{doctype}
   , #{taskoky}
   , #{taskoit}
   , #{lmouser}
   , #{omsgkey, mode=OUT, jdbcType=VARCHAR}
   , #{oresult, mode=OUT, jdbcType=INTEGER}
)

select CONCAT(TS.COMPKEY, TS.TASKOKY, TS.TASKOIT) AS ROWKEY , TS.COMPKEY , TS.WAREKEY , TS.OWNERKY , SH.DCTCTYP , SH.DOCCATE , SH.DOCTYPE , TS.ALLGRKY , TS.PICKTYP , TS.TASKSTS , SH.SHPDCKY , IF(TRIM(TS.COOUTKY) = ' ' , TS.OERETKY , TS.COOUTKY) AS COOUTKY , (select CUNAMLC from MCUSMA where COMPKEY = SH.COMPKEY and OWNERKY = SH.OWNERKY and CUSTKEY = SH.CUSTKEY) as CUSTKEY , (select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and WAREKEY = SH.WAREKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE) as DOCTYNM , SUM(TS.FORDQTY) as FORDQTY , SUM(TS.TCMPQTY) as TCMPQTY , SUM(TS.DIFFQTY) as DIFFQTY from WTAKIT TS inner join MLOCMA m on TS.COMPKEY = m.COMPKEY and TS.WAREKEY = m.WAREKEY and TS.FRLOCKY = m.LOCAKEY and m.LOCTYPE != 'AUTOSTORE' inner join WSHPIT SH on SH.COMPKEY = TS.COMPKEY and SH.WAREKEY = TS.WAREKEY and SH.OWNERKY = TS.OWNERKY and SH.SHPDCKY = TS.SHPDCKY and SH.SHPDCIT = TS.SHPDCIT SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and SH.SHPDCST != 'CMP' and TS.DOCCATE = '500' and TS.DOCTYPE = '530'
and SH.OWNERKY = #{ownerky}
and SH.SHPPDAY between #{shppdayfrom} and #{shppdayto}
and TS.TASKSTS in
#{taskstsItem}
and SH.SHPDCKY = #{shpdcky}
and TS.PICKTYP = #{picktyp}
and TS.ALLGRKY = #{allgrky}
and TS.SKUDESC LIKE CONCAT('%' , #{skudesc} , '%')
group by TS.COMPKEY, SH.DCTCTYP, TS.DOCCATE, TS.DOCTYPE, TS.ALLGRKY, SH.COOUTKY , TS.OERETKY order by TS.COMPKEY, SH.ALLGRKY, SH.COOUTKY

select CONCAT(TS.COMPKEY, TS.TASKOKY, TS.TASKOIT) AS ROWKEY , TS.COMPKEY , TS.WAREKEY , TS.OWNERKY , TS.PICKTYP , (select OWNAMLC from MOWRMA where COMPKEY = TS.COMPKEY and OWNERKY = TS.OWNERKY) as OWNAMLC , SH.DCTCTYP , SH.DOCCATE , SH.DOCTYPE , TS.ALLGRKY , TS.TASKSTS , SH.SHPDCKY , SH.SHPDCIT , IF(TRIM(TS.COOUTKY) = ' ' , TS.OERETKY , TS.COOUTKY) AS COOUTKY , IF(TRIM(TS.COOUTIT) = 0 , TS.OERETIT , TS.COOUTIT) AS COOUTIT , SH.CUSTKEY , (select CUNAMLC from MCUSMA where COMPKEY = SH.COMPKEY and OWNERKY = SH.OWNERKY and CUSTKEY = SH.CUSTKEY) as CUSTNAM , (SELECT DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY AND WAREKEY = SH.WAREKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE) as DOCTYNM , TS.TASKSTS , TS.SKUMKEY , TS.SKUDESC , TS.LOTNMKY , (select LOCANAM from MLOCMA where COMPKEY = TS.COMPKEY AND WAREKEY = TS.WAREKEY and AREAKEY = TS.FRAREKY and ZONEKEY = TS.FRZONKY and LOCAKEY = TS.FRLOCKY) as FRLONAM , TS.FRAREKY , TS.FRZONKY , TS.FRLOCKY , TS.TOAREKY , TS.TOZONKY , TS.TOLOCKY , (select LOCANAM from MLOCMA where COMPKEY = TS.COMPKEY AND WAREKEY = TS.WAREKEY and AREAKEY = TS.TOAREKY and ZONEKEY = TS.TOZONKY and LOCAKEY = TS.TOLOCKY) as TOLONAM , TS.FORDQTY , TS.FUOMEKY , TS.FORDQTY as TCMPQTY , TS.DIFFQTY , TS.TUOMEKY , TS.SHPDCKY , TS.SHPDCIT , TS.TASKOKY , TS.TASKOIT , TS.TRUNTYP , TS.TRUNPID , TS.OWNERKY , TS.VENDKEY , TS.SIRBCOD , TS.PRODDAT , TS.SHELIFE , fn_com_todate(TS.EXPIDAT) as EXPIDAT , TS.RCVDCDT , TS.RCVFRDT , TS.LOTFRKY , TS.LOTAT01 , TS.LOTAT02 , TS.LOTAT03 , TS.LOTAT04 , TS.LOTAT05 , TS.LOTAT06 , TS.LOTAT07 , TS.LOTAT08 , TS.LOTAT09 , TS.LOTAT10 , TS.LOTAT11 , TS.LOTAT12 , TS.LOTAT13 , TS.LOTAT14 , TS.LOTAT15 , TS.LOTAT16 , TS.LOTAT17 , TS.LOTAT18 , TS.LOTAT19 , TS.LOTAT20 , TS.STKSTAT , TS.TASKG01 , TS.TASKG02 , TS.TASKG03 , TS.TASKG04 , TS.TASKG05 , TS.PARSNCD , TS.PARSNNM , TS.PKRSNCD , TS.PKRSNNM , TS.MOVTEAM , TS.MOVUSID , TS.MVSTDAT , TS.MVSTTIM , TS.MVEDDAT , TS.MVEDTIM , TS.EOASNKY , TS.EOASNIT , TS.RCVDCKY , TS.RCVDCIT , TS.REFPODC , TS.REFPOIT , TS.REFSODC , TS.REFSOIT , TS.REFDNDC , TS.REFDNIT , TS.REFSDDC , TS.REFSDIT , TS.STORFKY , TS.STKOTKY , TS.STKINKY , TS.UPDTCHK from WTAKIT TS inner join MLOCMA m on TS.COMPKEY = m.COMPKEY and TS.WAREKEY = m.WAREKEY and TS.FRLOCKY = m.LOCAKEY and m.LOCTYPE != 'AUTOSTORE' inner join WSHPIT SH on SH.COMPKEY = TS.COMPKEY and SH.WAREKEY = TS.WAREKEY and SH.OWNERKY = TS.OWNERKY and SH.SHPDCKY = TS.SHPDCKY and SH.SHPDCIT = TS.SHPDCIT SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and TS.DOCCATE = '500' and TS.DOCTYPE = '530' and SH.SHPDCST != 'CMP'
and SH.OWNERKY = #{ownerky}
and SH.SHPPDAY between #{shppdayfrom} and #{shppdayto}
and TS.TASKSTS in ('TASK', 'TSCOMP')
and TS.TASKSTS in
#{taskstsItem}
and SH.SHPDCKY = #{shpdcky}
and TS.PICKTYP = #{picktyp}
and TS.ALLGRKY = #{allgrky}
and TS.SKUDESC LIKE CONCAT('%' , #{skudesc} , '%')
order by TS.COMPKEY, TS.TASKOKY , TS.TASKOIT

update.foreach:
update WTAKIT
   set LMODATE = to_char(now(),'YYYYMMDD')
	 , LMOTIME = to_char(now(),'hh24miss')
	 , LMOUSER = #{item.userData.useract}
	 , TCMPQTY = #{item.tcmpqty}
	 , DIFFQTY = #{item.diffqty}
 where COMPKEY = #{item.compkey}
   and TASKOKY = #{item.taskoky}
   and TASKOIT = #{item.taskoit}
   and UPDTCHK = #{item.updtchk}

