 ( 
 	   #{compkey}
	 , #{warekey}
	 , #{doccate}
	 , #{doctype}
	 , #{taskoky}
	 , #{taskoit}
	 , #{userData.useract}
	 , #{omsgkey, mode=OUT, jdbcType=VARCHAR}
	 , #{oresult, mode=OUT, jdbcType=INTEGER}
 )

/* getWmo30HeadList */ /* 기존 쿼리는 wtakit 테이블의 모든 row를 group by 하여 wshpit로 조인하므로 속도저하 발생 wshpit기준으로 wtakit를 찾도록 쿼리 수정 */ SELECT CONCAT(SH.COMPKEY, SH.WAREKEY, SH.ALLGRKY, TK.PICKTYP) AS ROWKEY , SH.COMPKEY, SH.WAREKEY , SH.DOCCATE, SH.DOCTYPE , (SELECT CDCATE1 FROM V_MCODEM WHERE COMPKEY = SH.COMPKEY AND COMCDKY = 'TASKSTS' AND COMCDVL = TK.TASKSTS) AS SHPDCST , (select COMCDTX from V_MCODEM MC where MC.COMPKEY = SH.COMPKEY and MC.COMCDVL = TK.PICKTYP and MC.COMCDKY = 'PICKTYP') as PICKNAM , SH.SHPDCKY , SUM(TK.DIFFQTY) AS DIFFQTY , COUNT(DISTINCT TK.SKUMKEY) AS SKKYCNT , SUM(SH.SHCUQTY) AS SHCUQTY , SUM(SH.RGITQTY) AS RGITQTY , SUM(SH.SHALQTY) AS SHALQTY , SUM(SH.SHPKQTY) AS SHPKQTY , SUM(SH.SHDVSQT) AS SHDVSQT , SUM(SH.SHDVEQT) AS SHDVEQT , SUM(SH.SHCFQTY) AS SHCFQTY , TK.ALLGRKY , TK.PICKTYP , SUM(TK.FORDQTY) AS FORDQTY , SUM(TK.TCMPQTY) AS TCMPQTY , SUM(CASE WHEN TK.TASKSTS = 'SHPOUT' THEN TK.TCMPQTY ELSE 0 END) AS SOUTQTY , fn_com_todate(MIN(TK.CREDATE)) AS SHSDATE , fn_com_totime(MIN(TK.CRETIME)) AS SHSTIME , fn_com_todate(MAX(TK.LMODATE)) AS SHEDATE , fn_com_totime(MAX(TK.LMOTIME)) AS SHETIME , fn_sy_usernam(SH.COMPKEY, MAX(TK.LMOUSER)) AS SHENAME FROM WSHPIT SH INNER JOIN /* TASK가 분할될 경우 Wshpit 기준으로 Group by 해줌 */ ( SELECT TS.COMPKEY, TS.WAREKEY , TS.DOCCATE, TS.DOCTYPE , (SELECT CDCATE1 FROM V_MCODEM WHERE COMPKEY = SH.COMPKEY AND COMCDKY = 'TASKSTS' AND COMCDVL = TS.TASKSTS) AS SHPDCST , TS.SHPDCKY, TS.SHPDCIT , SUM(TS.DIFFQTY) AS DIFFQTY , COUNT(DISTINCT TS.SKUMKEY) AS SKKYCNT , TS.ALLGRKY , TS.PICKTYP , TS.TASKSTS , TS.SKUMKEY , TS.COOUTKY , TS.COOUTIT , SUM(TS.FORDQTY) AS FORDQTY , SUM(TS.TCMPQTY) AS TCMPQTY , SUM(CASE WHEN TS.TASKSTS = 'SHPOUT' THEN TS.TCMPQTY ELSE 0 END) AS SOUTQTY , MIN(TS.CREDATE) AS CREDATE , MIN(TS.CRETIME) AS CRETIME , MAX(TS.LMODATE) AS LMODATE , MAX(TS.LMOTIME) AS LMOTIME , MAX(TS.LMOUSER) AS LMOUSER FROM WSHPIT SH FORCE INDEX(IX_WSHPIT01) INNER JOIN WTAKIT TS ON SH.COMPKEY = TS.COMPKEY AND SH.WAREKEY = TS.WAREKEY AND SH.COOUTKY = TS.COOUTKY AND SH.COOUTIT = TS.COOUTIT AND SH.SHPDCKY = TS.SHPDCKY AND SH.SHPDCIT = TS.SHPDCIT
AND TS.TASKSTS NOT in ('CANCEL', 'SHPOUT')
AND TS.TASKSTS NOT in ('CANCEL', 'TASK')
AND TS.DOCCATE = '500' AND TS.DOCTYPE = '530' AND TS.PICKTYP = 'SINGLE'
and TS.ALLGRKY = #{allgrky}
AND TS.ALLGRKY IN ( SELECT DISTINCT(TS.ALLGRKY) FROM WSHPIT SH INNER JOIN WTAKIT TS ON SH.COMPKEY = TS.COMPKEY AND SH.WAREKEY = TS.WAREKEY AND SH.SHPDCKY = TS.SHPDCKY AND SH.SHPDCIT = TS.SHPDCIT
AND TS.TASKSTS NOT in ('CANCEL', 'SHPOUT')
AND TS.TASKSTS NOT in ('CANCEL', 'TASK')
AND TS.DOCCATE = '500' AND TS.DOCTYPE = '530' WHERE SH.COMPKEY = #{userData.compkey} AND SH.WAREKEY = #{warekey} AND SH.DOCCATE = '700' AND SH.DOCTYPE in ('710','720', '730', '750', '760','790')
and TS.ALLGRKY = #{allgrky}
and TS.PICKTYP = #{picktyp}
and SH.SHPPDAY between #{shsdatefrom} and #{shsdateto}
and SH.COOUTKY = #{cooutky}
AND TS.OWNERKY = #{ownerky} )
WHERE SH.COMPKEY = #{userData.compkey} AND SH.WAREKEY = #{warekey} AND SH.DOCCATE = '700' AND SH.DOCTYPE IN ('710','720', '730', '750', '760' ,'790')
and SH.COOUTKY = #{cooutky}
and TS.PICKTYP = #{picktyp}
and SH.SHPPDAY between #{shsdatefrom} and #{shsdateto}
GROUP BY TS.COMPKEY, TS.WAREKEY, TS.DOCCATE, TS.DOCTYPE, TS.ALLGRKY, TS.PICKTYP, TS.SHPDCKY, TS.SHPDCIT, TS.COOUTKY, TS.COOUTIT ) TK ON SH.COMPKEY = TK.COMPKEY AND SH.WAREKEY = TK.WAREKEY AND SH.COOUTKY = TK.COOUTKY AND SH.COOUTIT = TK.COOUTIT AND SH.SHPDCKY = TK.SHPDCKY AND SH.SHPDCIT = TK.SHPDCIT GROUP BY SH.COMPKEY, SH.WAREKEY, TK.ALLGRKY, TK.PICKTYP

/* getWmo30ItemList */ select concat(SH.COMPKEY, SH.WAREKEY, SH.ALLGRKY, TS.PICKTYP) as ROWKEY , TS.COMPKEY, TS.WAREKEY , TS.DOCCATE, TS.DOCTYPE , (select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE and WAREKEY = SH.WAREKEY) as DOCTYNM , (select OWNAMLC from MOWRMA where COMPKEY = SH.COMPKEY and OWNERKY = SH.OWNERKY ) as OWNAMLC , (SELECT CDCATE1 FROM V_MCODEM WHERE COMPKEY = SH.COMPKEY AND COMCDKY = 'TASKSTS' AND COMCDVL = TS.TASKSTS) AS SHPDCST , TS.SHPDCKY, TS.SHPDCIT , SUM(TS.DIFFQTY) AS DIFFQTY , COUNT(DISTINCT TS.SKUMKEY) AS SKKYCNT , TS.ALLGRKY , TS.PICKTYP , TS.TASKSTS , TS.SKUMKEY , TS.SKUDESC , TS.COOUTKY , TS.COOUTIT , SH.DESTKEY , (select denamlc from MDESMA WHERE COMPKEY = SH.COMPKEY and PTNRKEY = SH.CUSTKEY and DESTKEY = SH.DESTKEY) as DENAMLC , SH.SHCUQTY , SH.RGITQTY , SH.SHALQTY , SUM(TS.FORDQTY) AS FORDQTY , SUM(TS.TCMPQTY) AS TCMPQTY , SUM(CASE WHEN TS.TASKSTS = 'SHPOUT' THEN TS.TCMPQTY ELSE 0 END) AS SOUTQTY , fn_com_todate(min(TS.CREDATE)) as SHSDATE , fn_com_totime(min(TS.CRETIME)) as SHSTIME , fn_com_todate(max(TS.LMODATE)) as SHEDATE , fn_com_totime(max(TS.LMOTIME)) as SHETIME , max(TS.LMOUSER) as SHEUSER , fn_sy_usernam(SH.COMPKEY, max(TS.LMOUSER)) as SHENAME FROM WSHPIT SH INNER JOIN WTAKIT TS ON SH.COMPKEY = TS.COMPKEY AND SH.WAREKEY = TS.WAREKEY AND SH.COOUTKY = TS.COOUTKY AND SH.COOUTIT = TS.COOUTIT AND SH.SHPDCKY = TS.SHPDCKY AND SH.SHPDCIT = TS.SHPDCIT
AND TS.TASKSTS not in ('CANCEL', 'TASK')
AND TS.TASKSTS not in ('CANCEL' , 'SHPOUT')
AND TS.DOCCATE = '500' AND TS.DOCTYPE = '530'
and TS.PICKTYP = #{picktyp}
AND trim(TS.ALLGRKY) like concat('%',#{allgrky},'%')
AND TS.ALLGRKY IN ( SELECT DISTINCT(TS.ALLGRKY) FROM WSHPIT SH INNER JOIN WTAKIT TS ON SH.COMPKEY = TS.COMPKEY AND SH.WAREKEY = TS.WAREKEY AND SH.SHPDCKY = TS.SHPDCKY AND SH.SHPDCIT = TS.SHPDCIT
AND TS.TASKSTS not in ('CANCEL', 'TASK')
AND TS.TASKSTS not in ('CANCEL' , 'SHPOUT')
AND TS.DOCCATE = '500' AND TS.DOCTYPE = '530' WHERE SH.COMPKEY = #{userData.compkey} AND SH.WAREKEY = #{warekey} AND SH.DOCCATE = '700' AND SH.DOCTYPE in ('710','720','730','750','760','790')
AND SH.SHPPDAY between #{shsdatefrom} and #{shsdateto}
and TS.ALLGRKY = #{allgrky}
and TS.PICKTYP = #{picktyp}
AND TS.OWNERKY = #{ownerky} )
WHERE SH.COMPKEY = #{userData.compkey} AND SH.WAREKEY = #{warekey} AND SH.DOCCATE = '700' AND SH.DOCTYPE in ('710','720','730','750','760','790')
AND SH.SHPPDAY BETWEEN #{shsdatefrom} AND #{shsdateto}
GROUP BY TS.COMPKEY, TS.WAREKEY, TS.DOCCATE, TS.DOCTYPE, TS.ALLGRKY, TS.PICKTYP, TS.SHPDCKY, TS.SHPDCIT, TS.COOUTKY, TS.COOUTIT ORDER BY TS.ALLGRKY ASC, SH.COOUTKY ASC , (CASE WHEN TS.OWNERKY = #{ownerky} THEN 1 ELSE 9 END), SH.COOUTIT ASC

