select CONCAT(SO.COMPKEY, SO.OERETKY , SO.OERETIT) as ROWKEY , SO.COMPKEY , SO.WAREKEY , SO.OWNERKY , SO.DOCCATE , SO.DOCTYPE , SO.DOCTYNM , SO.OERETKY , SO.OERETIT , SO.SHPDCKY , SO.DCTCTYP , SO.PICKTYP , COUNT(SO.OERETKY) as REFSCNT , MIN(SO.STOCKYN) as STOCKYN , SUM(SO.SHCUQTY) as SHCUQTY , SUM(SO.RGITQTY) as RGITQTY , SUM(SO.SHALQTY) as SHALQTY , fn_com_todate(SO.SALRQDT) as SALRQDT , fn_com_totime(SO.SALRQTM) as SALRQTM , SO.UPDTCHK from ( select SH.COMPKEY , SH.DOCCATE , SH.DOCTYPE , ( select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and WAREKEY = SH.WAREKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE ) as DOCTYNM, SH.WAREKEY , SH.OWNERKY , SH.CUSTKEY , SH.COOUTKY , SH.COOUTIT , SH.OERETKY , SH.OERETIT , SH.SHPDCKY , SH.SHPDCIT , SH.PICKTYP , SH.DCTCTYP , SH.SKUMKEY , (case when IFNULL(ST.TOTQTY,0) - SH.RGITQTY - SH.SHALQTY < 0 then 'N' else 'Y' end) as STOCKYN, IFNULL(ST.TOTQTY,0) , SH.SHCUQTY , SH.RGITQTY , SH.SHALQTY , SH.SALRQDT , SH.SALRQTM , SH.UPDTCHK from WSHPIT SH FORCE INDEX(IX_WSHPIT01) inner join MSKUWC MS on MS.COMPKEY = SH.COMPKEY and MS.WAREKEY = SH.WAREKEY and MS.OWNERKY = SH.OWNERKY and MS.SKUMKEY = SH.SKUMKEY left join ( select COMPKEY , OWNERKY , WAREKEY , SKUMKEY , SKUDESC , LOTAT17 , LOTAT18 , LOTAT19 , LOTAT20 , (sum(STOTQTY)- sum(SBLOQTY)) as TOTQTY from WSTKKY FORCE INDEX(IX_WSTKKY02) where COMPKEY = #{userData.compkey} and WAREKEY = #{warekey} and AREAKEY = 'STG' and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by COMPKEY , WAREKEY , OWNERKY , SKUMKEY , LOTAT17 , LOTAT18 , LOTAT19 , LOTAT20 ) ST on SH.COMPKEY = ST.COMPKEY and SH.WAREKEY = ST.WAREKEY and SH.OWNERKY = ST.OWNERKY and SH.SKUMKEY = ST.SKUMKEY and (case when SH.DCTCTYP = 'TC' then SH.COOUTKY else ' ' end) = ST.LOTAT19 and (case when SH.DCTCTYP = 'TC' then SH.COOUTIT else ' ' end) = ST.LOTAT20 SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and SH.DOCCATE = '700' and SH.DOCTYPE in ('780', '781')
and SH.SHPDCKY = #{shpdcky}
and SH.SHPPDAY between #{shppdayfrom} and #{shppdayto}
and SH.PICKTYP = #{picktyp}
and SH.SHPDCST in
#{shpdcstItem}
and SH.SHPITST in
#{shpdcstItem}
, 'F_ALOC'
) SO group by SO.SHPDCKY , SO.SHPDCIT order by SO.SHPDCKY , SO.SHPDCIT

select CONCAT(SH.COMPKEY, SH.OERETKY, SH.OERETIT) as ROWKEY , SH.COMPKEY , SH.COMPKEY , SH.DOCCATE , SH.DOCTYPE , SH.SHPDCKY , SH.SHPDCIT , SH.SHPDCST , SH.SHPITST , (select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE and WAREKEY = SH.WAREKEY) as DOCTYNM , SH.WAREKEY , SH.OWNERKY , (select OWNAMLC from MOWRMA where COMPKEY = SH.COMPKEY and OWNERKY = SH.OWNERKY) as OWNAMLC , SH.OERETKY , SH.OERETIT , SH.DCTCTYP , SH.PICKTYP , SH.SKUMKEY , SH.SKUDESC , (select SUOMKEY from MSKUWC where COMPKEY = SH.COMPKEY and WAREKEY = SH.WAREKEY and OWNERKY = SH.OWNERKY and SKUMKEY = SH.SKUMKEY ) as SUOMKEY , (case when IFNULL(ST.TOTQTY,0) - SH.RGITQTY - SH.SHALQTY < 0 then 'N' else 'Y' end) as STOCKYN , IFNULL(ST.TOTQTY,0) as STOCKCT , SH.SHCUQTY , SH.RGITQTY , SH.SHALQTY , SH.SHPKQTY , SH.ALLGRKY , fn_com_todate(SH.SALRQDT) as SALRQDT , fn_com_totime(SH.SALRQTM) as SALRQTM , fn_com_todate(SH.SHPPDAY) as SHPPDAY , fn_com_totime(SH.SHPPTIM) as SHPPTIM , fn_com_todate(SH.SHPSDAY) as SHPSDAY , fn_com_totime(SH.SHPSTIM) as SHPSTIM , SH.SPEHTIM , SH.SPEITIM , ' ' as ALSTRKY , SH.UPDTCHK from WSHPIT SH FORCE INDEX(IX_WSHPIT01) left join ( select t.COMPKEY , t.WAREKEY , t.OWNERKY , t.SKUMKEY , t.SHPDCKY , t.SHPDCIT , t.ALLGRKY , t.OERETKY , t.OERETIT , SUM(t.FORDQTY) AS FORDQTY, SUM(t.TCMPQTY) AS TCMPQTY from WTAKIT t where t.COMPKEY = #{userData.compkey} and t.WAREKEY = #{warekey} and t.DOCCATE = '500' and t.DOCTYPE = '530' and t.TASKSTS IN ('NEW' , 'TASK' , 'TSCOMP') group by t.COMPKEY, t.WAREKEY, t.OWNERKY, t.SKUMKEY, t.SHPDCKY, t.SHPDCIT, t.OERETKY, t.OERETIT, t.ALLGRKY ) TK on SH.COMPKEY = TK.COMPKEY and SH.WAREKEY = TK.WAREKEY and SH.OWNERKY = TK.OWNERKY and SH.SKUMKEY = TK.SKUMKEY and SH.SHPDCKY = TK.SHPDCKY and SH.SHPDCIT = TK.SHPDCIT and SH.OERETKY = TK.OERETKY and SH.OERETIT = TK.OERETIT and SH.ALLGRKY = TK.ALLGRKY left join ( select COMPKEY , OWNERKY , WAREKEY , SKUMKEY , SKUDESC , LOTAT17 , LOTAT18 , LOTAT19 , LOTAT20 , (sum(STOTQTY)- sum(SBLOQTY)) as TOTQTY from WSTKKY FORCE INDEX(IX_WSTKKY02) where COMPKEY = #{userData.compkey} and WAREKEY = #{warekey} and AREAKEY = 'STG' and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by COMPKEY , WAREKEY , OWNERKY , SKUMKEY, LOTAT17 , LOTAT18 , LOTAT19 , LOTAT20 ) ST on SH.COMPKEY = ST.COMPKEY and SH.WAREKEY = ST.WAREKEY and SH.SKUMKEY = ST.SKUMKEY and (case when SH.DCTCTYP = 'TC' then SH.OERETKY else ' ' end) = ST.LOTAT19 and (case when SH.DCTCTYP = 'TC' then SH.OERETIT else ' ' end) = ST.LOTAT20 SH.COMPKEY = #{userData.compkey} and SH.WAREKEY = #{warekey} and SH.DOCCATE = '700' and SH.DOCTYPE in ('780', '781')
and SH.SHPDCKY like concat('%' , #{shpdcky} , '%')
and SH.SHPPDAY between #{shppdayfrom} and #{shppdayto}
and SH.PICKTYP = #{picktyp}
and SH.SHPDCST in
#{shpdcstItem}
and SH.SHPITST in
#{shpdcstItem}
, 'F_ALOC'
order by SH.OERETKY , SH.OERETIT

update.foreach:
    	update WSHPIT
		   set LMODATE = to_char(now(),'YYYYMMDD')
			 , LMOTIME = to_char(now(),'hh24miss')
			 , LMOUSER = #{item.userData.useract}
			 , RGITQTY = #{item.rgitqty}
			 , ALLGRKY = #{item.allgrky}
			 , PICKTYP = #{item.picktyp}
    	 where COMPKEY = #{item.compkey}
    	   and OWNERKY = #{item.ownerky}
    	   and WAREKEY = #{item.warekey}
    	   and SHPDCKY = #{item.shpdcky}
    	   and SHPDCIT = #{item.shpdcit}
    	   and UPDTCHK = #{item.updtchk}

 	update WSHPIT
		   set LMODATE = to_char(now(),'YYYYMMDD')
 		 , LMOTIME = to_char(now(),'hh24miss')
 		 , LMOUSER = #{item.userData.useract}
 		 , SHPDCST = (
 						select  
                           case when sum(SHALQTY) > 0 then 
                              case when sum(RGITQTY) = sum(SHALQTY) then 'F_ALOC'
                              else 'P_ALOC' end 
                           else 'NEW' end 
                           from  WSHPIT
                           where SHPDCKY = #{item.shpdcky}
                           group by SHPDCKY 
                     )
 	where COMPKEY = #{item.compkey}
 	and OWNERKY = #{item.ownerky}
 	and WAREKEY = #{item.warekey}
 	and SHPDCKY = #{item.shpdcky}
	    and UPDTCHK = #{item.updtchk}

