and SH.SHPPDAY between #{shppdayfrom} and #{shppdayto}
GROUP BY TS.COMPKEY, TS.WAREKEY, TS.DOCCATE, TS.DOCTYPE, TS.ALLGRKY, TS.PICKTYP, TS.SHPDCKY, TS.SHPDCIT, TS.OERETKY, TS.OERETIT ) TK ON SH.COMPKEY = TK.COMPKEY AND SH.WAREKEY = TK.WAREKEY AND SH.OERETKY = TK.OERETKY AND SH.OERETIT = TK.OERETIT AND SH.SHPDCKY = TK.SHPDCKY AND SH.SHPDCIT = TK.SHPDCIT GROUP BY SH.COMPKEY, SH.WAREKEY, TK.ALLGRKY, TK.PICKTYP

/* getWmo51ItemList */ select concat(SH.COMPKEY, SH.WAREKEY, SH.ALLGRKY, TS.PICKTYP) as ROWKEY , TS.COMPKEY, TS.WAREKEY , TS.DOCCATE, TS.DOCTYPE , (select DOCTYNM from MDOCMA where COMPKEY = SH.COMPKEY and DOCCATE = SH.DOCCATE and DOCTYPE = SH.DOCTYPE and WAREKEY = SH.WAREKEY) as DOCTYNM , (select OWNAMLC from MOWRMA where COMPKEY = SH.COMPKEY and OWNERKY = SH.OWNERKY ) as OWNAMLC , (SELECT CDCATE1 FROM V_MCODEM WHERE COMPKEY = SH.COMPKEY AND COMCDKY = 'TASKSTS' AND COMCDVL = TS.TASKSTS) AS SHPDCST , TS.SHPDCKY, TS.SHPDCIT , SUM(TS.DIFFQTY) AS DIFFQTY , COUNT(DISTINCT TS.SKUMKEY) AS SKKYCNT , TS.ALLGRKY , TS.PICKTYP , TS.TASKSTS , TS.SKUMKEY , TS.SKUDESC , (select LOCANAM from MLOCMA ML where ML.COMPKEY = TS.COMPKEY and ML.WAREKEY = TS.WAREKEY and ML.AREAKEY = TS.TOAREKY and ML.ZONEKEY = TS.TOZONKY and ML.LOCAKEY = TS.TOLOCKY) as LOCANAM , TS.OERETKY , TS.OERETIT , SH.DESTKEY , (select denamlc from MDESMA WHERE COMPKEY = SH.COMPKEY and PTNRKEY = SH.CUSTKEY and DESTKEY = SH.DESTKEY) as DENAMLC , SH.SHCUQTY , SH.RGITQTY , SH.SHALQTY , SUM(TS.FORDQTY) AS FORDQTY , SUM(TS.TCMPQTY) AS TCMPQTY , SUM(CASE WHEN TS.TASKSTS = 'SHPOUT' THEN TS.TCMPQTY ELSE 0 END) AS SOUTQTY , fn_com_todate(min(TS.CREDATE)) as SHSDATE , fn_com_totime(min(TS.CRETIME)) as SHSTIME , fn_com_todate(max(TS.LMODATE)) as SHEDATE , fn_com_totime(max(TS.LMOTIME)) as SHETIME , max(TS.LMOUSER) as SHEUSER , fn_sy_usernam(SH.COMPKEY, max(TS.LMOUSER)) as SHENAME FROM WSHPIT SH INNER JOIN WTAKIT TS ON SH.COMPKEY = TS.COMPKEY AND SH.WAREKEY = TS.WAREKEY AND SH.OERETKY = TS.OERETKY AND SH.OERETIT = TS.OERETIT AND SH.SHPDCKY = TS.SHPDCKY AND SH.SHPDCIT = TS.SHPDCIT
AND TS.TASKSTS not in ('CANCEL', 'TASK')
AND TS.TASKSTS not in ('CANCEL' , 'SHPOUT')
AND TS.DOCCATE = '500' AND TS.DOCTYPE = '530'
and TS.PICKTYP = #{picktyp}
AND trim(TS.ALLGRKY) like concat('%',#{allgrky},'%')
AND TS.ALLGRKY IN ( SELECT DISTINCT(TS.ALLGRKY) FROM WSHPIT SH INNER JOIN WTAKIT TS ON SH.COMPKEY = TS.COMPKEY AND SH.WAREKEY = TS.WAREKEY AND SH.SHPDCKY = TS.SHPDCKY AND SH.SHPDCIT = TS.SHPDCIT
AND TS.TASKSTS not in ('CANCEL', 'TASK')
AND TS.TASKSTS not in ('CANCEL' , 'SHPOUT')
AND TS.DOCCATE = '500' AND TS.DOCTYPE = '530' WHERE SH.COMPKEY = #{userData.compkey} AND SH.WAREKEY = #{warekey} AND SH.DOCCATE = '700' AND SH.DOCTYPE in ('780', '781')
AND SH.SHPPDAY between #{shppdayfrom} and #{shppdayto}
and TS.ALLGRKY = #{allgrky}
and TS.PICKTYP = #{picktyp}
AND TS.OWNERKY = #{ownerky} )
WHERE SH.COMPKEY = #{userData.compkey} AND SH.WAREKEY = #{warekey} AND SH.DOCCATE = '700' AND SH.DOCTYPE in ('780', '781')
AND SH.SHPPDAY BETWEEN #{shppdayfrom} AND #{shppdayto}
GROUP BY TS.COMPKEY, TS.WAREKEY, TS.DOCCATE, TS.DOCTYPE, TS.ALLGRKY, TS.PICKTYP, TS.SHPDCKY, TS.SHPDCIT, TS.OERETKY, TS.OERETIT ORDER BY OERETKY ASC , (CASE WHEN TS.OWNERKY = #{ownerky} THEN 1 ELSE 9 END), OERETIT ASC

CALL sp_wm_shipout
( 
	  #{compkey}
	, #{warekey}
	, #{doccate}
	, #{doctype}
	, #{allgrky}
	, #{oeretky}
	, #{oeretit}
	, #{lmouser}
	, #{omsgkey, mode=OUT, jdbcType=VARCHAR}
	, #{oresult, mode=OUT, jdbcType=INTEGER}
)

/* getWmo60WshpitList */ SELECT OC.COMPKEY , OC.DOCCATE, OC.DOCTYPE , OC.SHPDCKY, OC.SHPDCIT , (select WHNAMLC from MWARMA W where W.COMPKEY = OC.COMPKEY and W.WAREKEY = OC.WAREKEY) as WAREKEY , (select COMCDTX from V_MCODEM where COMPKEY = OC.COMPKEY and COMCDKY = 'SHPITST' and COMCDVL = OC.SHPITST) as SHPITST , (select DOCCTNM from MDOCMA where COMPKEY = OC.COMPKEY and WAREKEY = OC.WAREKEY and DOCCATE = OC.DOCCATE and DOCTYPE = OC.DOCTYPE) AS DOCCTNM , (select DOCTYNM from MDOCMA where COMPKEY = OC.COMPKEY and WAREKEY = OC.WAREKEY and DOCCATE = OC.DOCCATE and DOCTYPE = OC.DOCTYPE) AS DOCTYNM , (select OWNAMLC from MOWRMA where COMPKEY = OC.COMPKEY and OWNERKY = OC.OWNERKY) as OWNERKY , fn_com_todate(OC.SPEIDAT) as SPEIDAT , OC.SKUMKEY , OC.SKUDESC , OC.COOUTKY, OC.COOUTIT , OC.OERETKY, OC.OERETIT , OC.SKUAT01 , OC.SKUAT03 , OC.SAATC06 , OC.SAATC10 , OC.FORDQTY , OC.TCMPQTY , fn_com_todate(OC.CREDATE) as CREDATE , fn_com_totime(OC.CRETIME) as CRETIME , fn_sy_usernam(OC.COMPKEY , OC.CREUSER) as CREUSER , fn_com_todate(OC.LMODATE) as LMODATE , fn_com_totime(OC.LMOTIME) as LMOTIME , fn_sy_usernam(OC.COMPKEY , OC.LMOUSER) as LMOUSER FROM ( SELECT SH.COMPKEY, SH.WAREKEY, SH.OWNERKY , SH.DOCCATE, SH.DOCTYPE, SH.SHPITST , SH.SHPDCKY, SH.SHPDCIT , SUM(WT.FORDQTY) AS FORDQTY , SUM(WT.TCMPQTY) AS TCMPQTY , SH.SKUMKEY , MK.SKUDESC , MK.SKUAT01 , MK.SKUAT03 , OS.SAATC06, OS.SAATC10 , SH.SPEIDAT , SH.COOUTKY, SH.COOUTIT , SH.OERETKY, SH.OERETIT , MIN(SH.CREDATE) AS CREDATE , MIN(SH.CRETIME) AS CRETIME , MIN(SH.CREUSER) AS CREUSER , MAX(SH.LMODATE) AS LMODATE , MAX(SH.LMOTIME) AS LMOTIME , MAX(SH.LMOUSER) AS LMOUSER FROM WSHPIT SH FORCE INDEX(IX_WSHPIT06) INNER JOIN WTAKIT WT FORCE INDEX (IX_WTAKIT06) ON SH.COMPKEY = WT.COMPKEY AND SH.WAREKEY = WT.WAREKEY AND SH.COOUTKY = WT.COOUTKY AND SH.COOUTIT = WT.COOUTIT AND SH.OERETKY = WT.OERETKY AND SH.OERETIT = WT.OERETIT INNER JOIN OCOSAL OS FORCE INDEX (IX_OCOSAL10) ON SH.COMPKEY = OS.COMPKEY AND SH.WAREKEY = OS.TOWARKY AND SH.COOUTKY = OS.COOUTKY AND SH.COOUTIT = OS.COOUTIT LEFT JOIN OERETI OT ON SH.COMPKEY = OT.COMPKEY AND SH.WAREKEY = OT.WAREKEY AND SH.OERETKY = OT.OERETKY AND SH.OERETIT = OT.OERETIT INNER join MSKUWC MK ON SH.COMPKEY = MK.COMPKEY AND SH.WAREKEY = MK.WAREKEY AND SH.OWNERKY = MK.OWNERKY AND SH.SKUMKEY = MK.SKUMKEY
SH.COMPKEY = #{userData.compkey}
and SH.OWNERKY = #{ownerky}
and SH.WAREKEY = #{warekey}
and SH.DOCTYPE in
#{item}
and SH.SHPITST in
#{item}
and MK.SKUMKEY like concat( '%' , #{skumkey} , '%')
and MK.SKUDESC like concat( '%' , #{skudesc} , '%')
and MK.SKUAT01 like concat( '%' , #{skuat01} , '%')
and (MK.SKUAT03 like concat( '%' , #{skuat03} , '%') OR OT.RETAT01 like concat( '%' , #{skuat03} , '%'))
and OS.SAATC10 like concat( '%' , #{saatc10} , '%')
and OS.SAATC06 like concat( '%' , #{saatc06} , '%')
and SH.SPEIDAT between replace(#{datefrom}, '-' , '') and replace(#{dateto}, '-' , '')
GROUP BY SH.COMPKEY, SH.WAREKEY, SH.OWNERKY , SH.DOCCATE, SH.DOCTYPE, SH.SHPITST , SH.SHPDCKY, SH.SHPDCIT , SH.SKUMKEY , MK.SKUDESC , MK.SKUAT01 , MK.SKUAT03 , SH.SPEIDAT , SH.COOUTKY, SH.COOUTIT , SH.OERETKY, SH.OERETIT , OS.SAATC06, OS.SAATC10 ) AS OC

